import { Agent, Workflow, VectorStore, ChatMemory } from 'mastra';
import { OpenAI } from 'mastra/llms';

const vectorStore = new VectorStore({
  embeddingModel: 'text-embedding-ada-002',
  collection: 'chatbot-knowledge'
});

const memory = new ChatMemory({ sessionTtl: '1h' });

const llm = new OpenAI({ model: 'gpt-4-turbo' });

const ragWorkflow = new Workflow({
  nodes: {
    classify: {
      llm,
      prompt: 'Classify intent: {{input}}',
      outputSchema: z.object({ intent: z.string(), confidence: z.number() })
    },
    retrieve: {
      vectorStore,
      topK: 5,
      filter: ({ intent }) => ({ metadata: { intent } })
    },
    generate: {
      llm,
      prompt: `Context: {{retrieved}}
History: {{memory}}
User: {{input}}
Respond helpfully:`
    }
  }
});

export const chatbot = new Agent({
  workflow: ragWorkflow,
  memory,
  llm
});

import { z } from 'zod';

const intentSchema = z.object({
  intent: z.enum(['greeting', 'query', 'support', 'booking']),
  confidence: z.number().min(0.7),
  entities: z.array(z.object({ type: z.string(), value: z.string() }))
});

const classifyNode = {
  name: 'classify',
  type: 'llm',
  llm,
  prompt: `Classify this message and extract entities:
{{input}}

Respond as JSON with intent, confidence (0-1), and entities array.`,
  outputParser: intentSchema,
  onError: (error, ctx) => {
    console.error('Classification failed:', error);
    return { intent: 'unknown', confidence: 0.1 };
  }
};

const retrievalNode = {
  name: 'retrieve',
  type: 'retrieval',
  vectorStore,
  inputKey: 'query',
  topK: 3,
  metadataFilter: ({ intent }) => ({
    intent,
    recency: { $gte: Date.now() - 24*60*60*1000 }
  }),
  augment: async (docs, { memory }) => {
    const context = [
      ...docs.map(d => d.pageContent),
      `Recent conversation: ${memory.slice(-3).map(m => m.content).join('\n')}`
    ];
    return { retrieved: context.join('\n---\n'), sources: docs.map(d => d.metadata) };
  }
};

const generateNode = {
  name: 'generate',
  type: 'llm',
  llm,
  prompt: `CONTEXT: {{retrieved}}

CONVERSATION HISTORY: {{memory}}

USER: {{input}}

{{#if safety_check.passed}}
Generate a helpful, accurate response. Cite sources using [1], [2] etc.
{{else}}
Respond: "Sorry, I can't assist with that request."
{{/if}}`,
  outputSchema: z.object({
    response: z.string().max(2000),
    citations: z.array(z.number()).optional(),
    safety_score: z.number().min(0).max(1)
  }),
  preprocess: async ({ safety_check }) => {
    const isSafe = await safetyFilter({ input: input, context: retrieved });
    return { ...input, safety_check: { passed: isSafe } };
  }
};

