import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  project: 'mastra-chatbot',
  riskProfile: 'high'
});

export const guardedChatbot = {
  async invoke(input: string, sessionId: string) {
    // Pre-execution input validation
    const cleanInput = await vex.verify({
      data: input,
      checks: ['pii_detection', 'safety_filter'],
      context: { sessionId, type: 'user_input' }
    });

    const result = await chatbot.invoke(cleanInput);

    // Post-execution response validation
    const verified = await vex.verify({
      data: result,
      checks: [
        'response_accuracy',
        'hallucination_detection',
        'conversation_coherence',
        'json_schema'
      ],
      context: {
        sessionId,
        workflowOutputs: result.workflowTrace,
        expectedSchema: generateSchema
      }
    });

    return verified;
  }
};

import { z } from 'zod';

const nodeSchemas = {
  classify: z.object({
    intent: z.enum(['greeting', 'query', 'support']),
    confidence: z.number().gte(0.6)
  }),
  retrieve: z.object({
    retrieved: z.string().min(10),
    sources: z.array(z.object({ url: z.string().url() }))
  })
};

const validatedWorkflow = ragWorkflow.mapNodes((node) => ({
  ...node,
  postprocess: async (output) => {
    const schema = nodeSchemas[node.name];
    const validation = schema.safeParse(output);

    if (!validation.success) {
      const fixed = await vex.verify({
        data: output,
        checks: ['json_schema_validation'],
        context: { expectedSchema: schema, node: node.name }
      });
      return fixed;
    }
    return output;
  }
}));

const verifiedMemory = {
  async retrieve(sessionId: string, query: string) {
    const chunks = await memory.retrieve(sessionId, { limit: 5 });

    const verifiedChunks = await vex.verify({
      data: chunks,
      checks: [
        'semantic_relevance',
        'temporal_freshness',
        'pii_redaction',
        'conversation_coherence'
      ],
      context: {
        query,
        sessionId,
        maxAge: 24 * 60 * 60 * 1000, // 24h
        relevanceThreshold: 0.75
      }
    });

    return verifiedChunks.filter(c => c.passed).slice(0, 3);
  }
};
